def solution(grid):
    # Number of islands using DFS flood-fill
    if not grid:
        return 0
    rows, cols = len(grid), len(grid[0])
    grid = [row[:] for row in grid]  # copy to avoid mutating input
    count = 0
    def dfs(r, c):
