def solution(n, edges):
    # Detect cycle in directed graph using DFS with color marking
    from collections import defaultdict
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
    # 0=unvisited, 1=in-stack, 2=done
    color = [0] * n
    def dfs(u):
        color[u] = 1
        for v in graph[u]:
            if color[v] == 1:
                return True
            if color[v] == 0 and dfs(v):
