def solution(n, edges):
    # Count connected components using Union-Find with path compression
    parent = list(range(n))
    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]  # path halving
            x = parent[x]
        return x
    def union(a, b):
        pa, pb = find(a), find(b)
        if pa == pb:
            return False
        parent[pa] = pb
        return True
    components = n
    for u, v in edges:
        if union(u, v):
            components -= 1
    return components
