def solution(n, edges):
    # Minimum spanning tree weight using Kruskal's algorithm
    edges = sorted(edges, key=lambda e: e[2])
    parent = list(range(n))
    rank = [0] * n
    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x
    def union(x, y):
        px, py = find(x), find(y)
        if px == py:
            return False
        if rank[px] < rank[py]:
            px, py = py, px
        parent[py] = px
        if rank[px] == rank[py]:
            rank[px] += 1
        return True
    total = 0
    edge_count = 0
    for u, v, w in edges:
        if union(u, v):
            total += w
            edge_count += 1
    return total if edge_count == n - 1 else -1
